import{_ as t,o as a,c as n,ae as r}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"What is a Self Attributing Network?","description":"","frontmatter":{"title":"What is a Self Attributing Network?","slug":"what-is-a-self-attributing-network"},"headers":[],"relativePath":"marketer-hub/what-is-a-self-attributing-network.md","filePath":"marketer-hub/what-is-a-self-attributing-network.md"}'),i={name:"marketer-hub/what-is-a-self-attributing-network.md"};function o(s,e,d,l,c,h){return a(),n("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Self Attributing Networks - commonly referred to as SANs - are unique in that they have infrastructure to track users &amp; conversions at both the web &amp; app level, so they can attribute downstream user behavior that occurs within their own ecosystem.</p><p>As such, SAN attribution is completed independently from a third party attribution provider - like Branch - which receives attribution confirmation directly from the SAN itself.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>.png&quot;)</p><p><strong>1.</strong> User interacts with a SAN mobile ad -&gt; is taken into your app -&gt; completes an in-app event.; e.g. a purchase.<br><strong>2.</strong> The SAN records and ingests the click/impression information associated with the in-app event.<br><strong>3.</strong> Simultaneously, the Branch SDK records the in-app event which is sent to the Branch servers.<br><strong>4.</strong> Branch sends device-level event data to the SAN via API to potentially be claimed by the SAN.<br><strong>5.</strong> If the SAN has touch data that corresponds to the device-level event data, the SAN sends Branch said touch data to use for attribution.<br><strong>6.</strong> Branch joins the SAN touch data with the event data on a per device basis after which the SAN attribution data is aggregated and displayed in your Branch dashboard.</p><p>In summary, Branch tracks app conversion events and sends them to the SANs enabled in your dashboard in bulk; the Ad Networks then claim the conversions they want to take credit for.</p><p>Branch adds value here by de-duplicating the attribution data across Ad Networks by cross-referencing event data across networks, giving credit based on event timestamps. For example, if Twitter and Facebook were claiming the same event, we’d credit the Ad Network with the last timestamp.</p><p>As SANs only have visibility into their own platform, conversion counts tend to be higher in their own reporting UI which is why 3rd party attribution providers like Branch exist.</p><h2 id="attribution-data-sent-between-branch-sans" tabindex="-1">Attribution Data Sent Between Branch &lt;&gt; SANs <a class="header-anchor" href="#attribution-data-sent-between-branch-sans" aria-label="Permalink to &quot;Attribution Data Sent Between Branch &lt;&gt; SANs&quot;">​</a></h2><h3 id="branch-data-sans" tabindex="-1">Branch Data -&gt; SANs <a class="header-anchor" href="#branch-data-sans" aria-label="Permalink to &quot;Branch Data -&gt; SANs&quot;">​</a></h3><ul><li><a href="https://developer.apple.com/documentation/iad/setting_up_apple_search_ads_attribution/#3342534" target="_blank" rel="noreferrer">Apple Ads</a> (client-side SDK attribution dictionary retrieval)</li><li>Facebook</li><li><a href="https://developers.google.com/app-conversion-tracking/api/request-response-specs#conversion_tracking_request" target="_blank" rel="noreferrer">Google Ads</a></li><li>Google Marketing Platform</li><li>Snap (available upon request)</li><li><a href="https://developer.twitter.com/en/docs/ads/measurement/api-reference/conversion-event#parameters" target="_blank" rel="noreferrer">Twitter</a></li></ul><h3 id="san-data-branch" tabindex="-1">SAN Data -&gt; Branch <a class="header-anchor" href="#san-data-branch" aria-label="Permalink to &quot;SAN Data -&gt; Branch&quot;">​</a></h3><ul><li><a href="https://developer.apple.com/documentation/iad/setting_up_apple_search_ads_attribution/#3341535" target="_blank" rel="noreferrer">Apple Ads</a> (Retrieved Attribution Dictionary via SDK)</li><li>Facebook</li><li><a href="https://developers.google.com/app-conversion-tracking/api/request-response-specs#conversion_tracking_response" target="_blank" rel="noreferrer">Google Ads</a></li><li>Google Marketing Platform</li><li>Snap (available upon request)</li><li><a href="https://developer.twitter.com/en/docs/ads/measurement/api-reference/conversion-event#example-response" target="_blank" rel="noreferrer">Twitter</a></li></ul><h3 id="san-cost-data" tabindex="-1">SAN Cost Data <a class="header-anchor" href="#san-cost-data" aria-label="Permalink to &quot;SAN Cost Data&quot;">​</a></h3><p>The following SANs also provide an endpoint for the retrieval of cost data:</p><ul><li>Apple Ads</li><li>Facebook</li><li>Google Ads</li><li>Snap</li><li>Tiktok</li></ul><p>For those SANs that send cost data, Branch provides the following metrics:</p><table tabindex="0"><thead><tr><th>Analytics Tag</th><th>Description</th><th>Used for</th></tr></thead><tbody><tr><td>Cost</td><td>Total cost (spend) for those dimensions (analytics tags, user data, time range), regardless of cost model</td><td>Understanding the total amount spent</td></tr><tr><td>eCPI</td><td>cost / installs</td><td>Normalizing spend per install, to understand the average price of an install across networks or over time</td></tr><tr><td>eCPC</td><td>cost / clicks</td><td>Normalizing spend per click, to understand the average price of an click across networks or over time</td></tr><tr><td>eCPM</td><td>cost / (impressions / 1000)</td><td>Normalizing spend per thousand impressions, to understand the average price of 1000 impressions across networks or over time</td></tr><tr><td>eCPA</td><td>cost / purchases [includes web and app purchases]</td><td>Normalizing spend per purchase, to understand the average price of a purchase across networks or over time</td></tr><tr><td>Return On Investment (ROI)</td><td>(revenue-cost / cost) * 100</td><td>Deriving return on investment, to understand the percentage &quot;profit&quot; made on ad spend</td></tr><tr><td>Return On Ad Spend (ROAS)</td><td>(revenue / cost) * 100</td><td>Deriving return on investment by understanding the percentage revenue multiple for a given unit of spend</td></tr></tbody></table><p><strong>NOTE</strong>: All cost data is ingested in local currency and then translated to USD on the dashboard using the exchange rate for that currency on the day the data is stored. In effect, this means the dashboard shows the amount that campaign cost converted to USD at the time it ran.</p><h2 id="using-branch-links" tabindex="-1">Using Branch Links <a class="header-anchor" href="#using-branch-links" aria-label="Permalink to &quot;Using Branch Links&quot;">​</a></h2><p>For those Self Attributing Networks that allow the use of 3rd party links in <strong>APP AD CAMPAIGNS</strong>, the Branch Link you provide can only be used for deep linking and not for attribution.</p><p>To ensure this, add <code>$deeplink_no_attribution=true</code> as a query parameter to the ad link you have created. Not doing so will cause any conversions resulting from said link to not be attributed.</p><p>For non-app ad campaigns - i.e. <strong>WEB CAMPAIGNS</strong> - you do not need to modify the Branch-generated link.</p><h2 id="agency-managed-san-campaigns" tabindex="-1">Agency-Managed SAN Campaigns <a class="header-anchor" href="#agency-managed-san-campaigns" aria-label="Permalink to &quot;Agency-Managed SAN Campaigns&quot;">​</a></h2><p>Only agencies managing advertising campaigns on behalf of a client must append their <strong>Agency ID</strong> to the campaign name when creating advertising campaigns for Self-Attributing Networks (SANs).</p><div class="danger custom-block"><p class="custom-block-title">Agency ID Required</p><p>Failure to append the campaign name with the <strong>Agency ID</strong> will result in any subsequent conversion not being properly attributed to the responsible agency.</p></div><h3 id="finding-your-agency-id" tabindex="-1">Finding Your Agency ID <a class="header-anchor" href="#finding-your-agency-id" aria-label="Permalink to &quot;Finding Your Agency ID&quot;">​</a></h3><p>You can find your Agency ID under Account Settings in the <a href="./entity-views-access-controls-overview.html">Agency view</a>.</p><h3 id="creating-your-agency-tag" tabindex="-1">Creating Your Agency Tag <a class="header-anchor" href="#creating-your-agency-tag" aria-label="Permalink to &quot;Creating Your Agency Tag&quot;">​</a></h3><p>Your agency tag <strong>must</strong> adhere to the following format:</p><p><code>agency_{YOUR AGENCY ID HERE}_</code></p><p><strong>Example Campaign with Agency tag</strong></p><p><code>agency_1234567890_My_SAN_Ad_Campaign</code></p><p><em>You can append the Agency Tag to either the</em> <em><strong>beginning</strong></em> <em>or the</em> <em><strong>end</strong></em> <em>of the campaign name.</em></p><p><strong>NOTE</strong>: The <code>~campaign</code> value displayed in exports/analytics will not include the agency_id. If you set up a campaign called <code>test_campaign_agency_1234</code> for a SAN, the <code>~campaign</code> value will be <code>test campaign</code> for any installs that came from that campaign.</p><h2 id="viewing-san-data-via-branch" tabindex="-1">Viewing SAN Data via Branch <a class="header-anchor" href="#viewing-san-data-via-branch" aria-label="Permalink to &quot;Viewing SAN Data via Branch&quot;">​</a></h2><p>Each SAN has its own requirements on how their attribution data can be handled by a third party. To learn the specifics for each SAN, please refer to the following:</p><ul><li><a href="./apple-search-ads.html">Apple Ads</a></li><li><a href="./facebook-ads-overview.html#viewing-facebook-data">Facebook Ads</a></li><li><a href="./google-ads-data-reporting.html">Google Ads</a></li><li><a href="./google-marketing-platform.html">Google Marketing Platform</a></li><li><a href="./snap.html#view-attribution-on-dashboard">Snap</a></li><li><a href="./twitter-ads.html#twitter-data-sharing">Twitter Ads</a></li></ul>',39)])])}const u=t(i,[["render",o]]);export{g as __pageData,u as default};
